class Solution {
    public int peopleAwareOfSecret(int n, int delay, int forget) {
        long[] dp = new long[n + 1];
        dp[1] = 1;
        long sum = 0;
        long mod = (long) (1e9 + 7);
        for (int i = 2; i <= n; i++) {
            if (i >= forget) {
                sum = (sum - dp[i - forget + 1] + mod) % mod;
            }
            if (i >= delay + 1) {
                sum = (sum + dp[i - delay]) % mod;
            }
            dp[i] = sum;
        }
        long res = 0;
        for (int i = n - forget + 1; i <= n; i++) {
            res = (res + dp[i]) % mod;
        }
        return (int) res;
    }
}
